/**
 * useTransactions.js
 * ─────────────────────────────────────────────────────────────
 * Hook centralizado para el estado de transacciones.
 * Las páginas consumen este hook en lugar de hacer fetch directo,
 * manteniendo la lógica de datos separada de la UI.
 */

import { useState, useEffect, useCallback } from 'react'
import {
  getTransactions,
  createTransaction,
  deleteTransaction,
  getSummary,
} from '../api/transactionApi'

/**
 * @param {object} filters — filtros opcionales para la query
 * @returns {{ transactions, summary, loading, error, addTransaction, removeTransaction, reload }}
 */
export const useTransactions = (filters = {}) => {
  const [transactions, setTransactions] = useState([])
  const [summary,      setSummary]      = useState(null)
  const [loading,      setLoading]      = useState(true)
  const [error,        setError]        = useState(null)

  /**
   * Carga transacciones y resumen en paralelo.
   * Usar Promise.all reduce el tiempo de carga a la mitad.
   */
  const load = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const [txRes, sumRes] = await Promise.all([
        getTransactions(filters),
        getSummary(),
      ])
      setTransactions(txRes.data   || [])
      setSummary(sumRes.data       || null)
    } catch (err) {
      setError(
        err.response?.data?.error ||
        'No se pudo conectar con el servidor. ¿Está corriendo el backend?'
      )
    } finally {
      setLoading(false)
    }
  }, [JSON.stringify(filters)]) // eslint-disable-line

  useEffect(() => { load() }, [load])

  /**
   * Agrega una transacción y recarga el estado.
   * @throws Error si el servidor responde con error
   */
  const addTransaction = async (payload) => {
    const res = await createTransaction(payload)
    await load()
    return res
  }

  /**
   * Elimina una transacción por ID.
   * Actualiza el estado localmente para respuesta inmediata,
   * luego recarga el resumen del servidor.
   */
  const removeTransaction = async (id) => {
    // Optimistic update: elimina del estado antes de la respuesta
    setTransactions((prev) => prev.filter((t) => t.id !== id))
    try {
      await deleteTransaction(id)
      // Recargar solo el resumen (más liviano que recargar todo)
      const sumRes = await getSummary()
      setSummary(sumRes.data || null)
    } catch (err) {
      // Si falla, recargar todo para restaurar estado correcto
      await load()
      throw err
    }
  }

  return {
    transactions,
    summary,
    loading,
    error,
    addTransaction,
    removeTransaction,
    reload: load,
  }
}
